data = {'a': 10, 'b': 20}
assert reverse_lookup(data, 20) == ['b']
assert reverse_lookup(data, 99) == []

try:
    dice_totals(-1)
    assert False, 'Expected ValueError.'
except ValueError:
    pass

for code in ['D1A 1A1', 'A12 3B4', 'A1A 1A', '']:
    try:
        describe_postal_code(code)
        assert False, f'Expected ValueError for {code!r}.'
    except ValueError:
        pass

for value in [-1, 1000, 4.2, '12']:
    try:
        number_to_words(value)
        assert False, 'Expected ValueError.'
    except ValueError:
        pass

base = {letter: [1, 2, 3, 4, 5] for letter in 'BINGO'}
h = {k: list(v) for k, v in base.items()}
for letter in 'BINGO': h[letter][2] = 0
assert is_winning_card(h) is True
v = {k: list(v) for k, v in base.items()}; v['N'] = [0] * 5
assert is_winning_card(v) is True

for positions in [range(5), reversed(range(5))]:
    card = {letter: [1, 2, 3, 4, 5] for letter in 'BINGO'}
    for letter, row in zip('BINGO', positions): card[letter][row] = 0
    assert is_winning_card(card) is True

for games in [0, -2, 1.5]:
    try:
        simulate_bingo(games)
        assert False, 'Expected ValueError.'
    except ValueError:
        pass
